[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/concept-scheme/iso3166-eu> ;
            sh:resultMessage "A codelist must declare at least one skos:hasTopConcept." ;
            sh:resultPath skos:hasTopConcept ;
            sh:resultSeverity sh:Violation ;
            sh:sourceConstraintComponent sh:ClassConstraintComponent ;
            sh:sourceShape _:n2b6fcc4a1a4c4bdbb9a76467f6f424fdb3 ;
            sh:value <https://example.org/concept/DE> ],
        [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/concept-scheme/iso3166-eu> ;
            sh:resultMessage "schema:dateModified is required (ISO 8601 date string)." ;
            sh:resultPath schema1:dateModified ;
            sh:resultSeverity sh:Violation ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ a sh:PropertyShape ;
                    sh:datatype xsd:string ;
                    sh:maxCount 1 ;
